const placeCorrectAnswer = (correct, wrong, index) => {
  const position = index % 4;
  const answers = [...wrong.slice(0, 3)];
  answers.splice(position, 0, correct);
  return { answers, correct: position };
};

const quizTasks = FILMS.flatMap((film, index) => {
  const [title, year, lead, dutchTitle] = film;
  const source = index < 55 ? CONTENT_SOURCES.disneyMovies : CONTENT_SOURCES.pixarFilms;
  const otherFilms = [1, 7, 13].map(offset => FILMS[(index + offset) % FILMS.length]);
  const easy = placeCorrectAnswer(dutchTitle, otherFilms.map(item => item[3]), index);
  const medium = placeCorrectAnswer(String(year), [String(year - 1), String(year + 1), String(year + 2)], index + 1);
  const hard = placeCorrectAnswer(
    `${title} — ${year}`,
    otherFilms.map((item, wrongIndex) => `${item[0]} — ${item[1] + wrongIndex + 1}`),
    index + 2
  );
  return [
    { id: `quiz-easy-${index + 51}`, cat: 'Quiz', type: 'quiz', difficulty: 'easy', title: 'Disney Filmquiz', text: `Welke oorspronkelijke animatiefilm uit ${year} hoort bij ${lead}?`, ...easy, points: 1, source },
    { id: `quiz-medium-${index + 51}`, cat: 'Quiz', type: 'quiz', difficulty: 'medium', title: 'Disney Filmgeschiedenis', text: `In welk jaar verscheen de oorspronkelijke animatiefilm ${title}?`, ...medium, points: 2, source },
    { id: `quiz-hard-${index + 51}`, cat: 'Quiz', type: 'quiz', difficulty: 'hard', title: 'Disney Archiefkenner', text: `Welke combinatie rond de filmgeschiedenis van ${lead} klopt?`, ...hard, points: 3, source },
  ];
});

