    id: `whoami-${index + 41}`,
    cat: 'Wie ben ik?',
    type: 'whoami',
    title: 'Hint Quest',
    hint1: WHOAMI_BROAD_HINTS[index % WHOAMI_BROAD_HINTS.length],
